/**
 * @summary List redemption history
 */
export const getListRedemptionsUrl = (params?: ListRedemptionsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/redemptions?${stringifiedParams}`
    : `/api/redemptions`;
};

export const listRedemptions = async (
  params?: ListRedemptionsParams,
  options?: RequestInit,
): Promise<Redemption[]> => {
  return customFetch<Redemption[]>(getListRedemptionsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListRedemptionsQueryKey = (params?: ListRedemptionsParams) => {
  return [`/api/redemptions`, ...(params ? [params] : [])] as const;
};

export const getListRedemptionsQueryOptions = <
  TData = Awaited<ReturnType<typeof listRedemptions>>,
  TError = ErrorType<unknown>,
>(
  params?: ListRedemptionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listRedemptions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListRedemptionsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listRedemptions>>> = ({
    signal,
  }) => listRedemptions(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listRedemptions>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListRedemptionsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listRedemptions>>
>;
export type ListRedemptionsQueryError = ErrorType<unknown>;

/**
 * @summary List redemption history
 */

export function useListRedemptions<
  TData = Awaited<ReturnType<typeof listRedemptions>>,
  TError = ErrorType<unknown>,
>(
  params?: ListRedemptionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listRedemptions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListRedemptionsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
